let bits = null;

function decode() {
  const raw = atob(LANDMASK_BASE64);
  const buffer = new Uint8Array(raw.length);
  for (let i = 0; i < raw.length; i += 1) buffer[i] = raw.charCodeAt(i);
  return buffer;
}

export function isLand(latDeg, lonDeg) {
  if (!bits) bits = decode();
  const x = Math.min(WIDTH - 1, Math.max(0, Math.floor(((lonDeg + 180) / 360) * WIDTH)));
  const y = Math.min(HEIGHT - 1, Math.max(0, Math.floor(((90 - latDeg) / 180) * HEIGHT)));
  const idx = y * WIDTH + x;
  return (bits[idx >> 3] & (1 << (idx & 7))) !== 0;
}
